    if (i == 0) {
        t = parseInt(line);
        i++;
    } else {
        let s = line;
        let n = s.length;
        let left = 0, right = n - 1;
        while (left < right && s[left] == s[right]) {
            left++;
            right--;
        }
        console.log(left + (n - right - 1));
        i++;
        if (i > t) {
